func generate_prime_numbers(n int) ([]int, error) {
	if n < 0 {
		return nil, fmt.Errorf("input must be a non-negative integer")
	}

	if n < 2 {
		return []int{}, nil
	}

	// Create a boolean slice to mark non-prime numbers
	isPrime := make([]bool, n+1)
	for i := 2; i <= n; i++ {
		isPrime[i] = true
	}

	// Sieve of Eratosthenes
	for i := 2; i*i <= n; i++ {
		if isPrime[i] {
			for j := i * i; j <= n; j += i {
				isPrime[j] = false
			}
		}
	}

	// Collect prime numbers
	primes := []int{}
	for i := 2; i <= n; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}

	return primes, nil
}
