use std::collections::{HashMap, BTreeMap};
use smallvec::SmallVec;

fn parse_http_request(raw_request: &str) -> (
    SmallVec<[(&str, &str); 8]>,
    HashMap<&str, &str>,
    Vec<&str>,
    BTreeMap<&str, &str>
) {
    let mut lines = raw_request.lines();

    // Skip request line
    let _ = lines.next();

    // Parse headers
    let mut common_headers: SmallVec<[(&str, &str); 8]> = SmallVec::new();
    let mut all_headers: HashMap<&str, &str> = HashMap::new();
    let mut raw_headers: Vec<&str> = Vec::new();
    let mut cookies: BTreeMap<&str, &str> = BTreeMap::new();

    for line in lines {
        if line.is_empty() {
            break;
        }

        raw_headers.push(line);

        if let Some(index) = line.find(':') {
            let (name, value) = line.split_at(index);
            let name = name.trim();
            let value = value[1..].trim();

            all_headers.insert(name, value);

            // Store common headers in SmallVec
            match name.to_lowercase().as_str() {
                "host" | "user-agent" | "accept" | "content-type" | 
                "content-length" | "connection" | "authorization" | "referer" => {
                    common_headers.push((name, value));
                },
                "cookie" => {
                    // Parse cookies
                    let cookie_pairs = value.split(';');
                    for pair in cookie_pairs {
                        if let Some(eq_index) = pair.find('=') {
                            let (cookie_name, cookie_value) = pair.split_at(eq_index);
                            cookies.insert(cookie_name.trim(), cookie_value[1..].trim());
                        }
                    }
                },
                _ => {}
            }
        }
    }

    (common_headers, all_headers, raw_headers, cookies)
}
