func calculate_response_stats(responseTimeMs []float64) (float64, float64, float64, int, error) {
	// Check if the input slice is empty
	if len(responseTimeMs) == 0 {
		return 0, 0, 0, 0, fmt.Errorf("input slice is empty")
	}

	// Calculate the total number of samples
	totalSamples := len(responseTimeMs)

	// Calculate the mean
	var sum float64
	for _, time := range responseTimeMs {
		sum += time
	}
	mean := sum / float64(totalSamples)

	// Sort the slice for median and percentile calculations
	sorted := make([]float64, totalSamples)
	copy(sorted, responseTimeMs)
	sort.Float64s(sorted)

	// Calculate the median
	var median float64
	if totalSamples%2 == 0 {
		median = (sorted[totalSamples/2-1] + sorted[totalSamples/2]) / 2
	} else {
		median = sorted[totalSamples/2]
	}

	// Calculate the 95th percentile
	p95Index := int(math.Ceil(float64(totalSamples)*0.95)) - 1
	if p95Index >= totalSamples {
		p95Index = totalSamples - 1
	}
	p95 := sorted[p95Index]

	return mean, median, p95, totalSamples, nil
}
