	statusCode := resp.StatusCode

	// Read response body
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return statusCode, "", false
	}
	responseMessage := string(bodyBytes)

	// Check cache policy
	cacheControl := resp.Header.Get("Cache-Control")
	canBeCached := true

	// Check for cache prevention directives
	if strings.Contains(cacheControl, "no-store") ||
		strings.Contains(cacheControl, "no-cache") ||
		strings.Contains(cacheControl, "private") ||
		strings.Contains(cacheControl, "max-age=0") {
		canBeCached = false
	}

	// Additional status code based cache determination
	if statusCode >= 400 || statusCode == 204 || statusCode == 304 {
		canBeCached = false
	}

	return statusCode, responseMessage, canBeCached
}
