use std::collections::{BTreeMap, VecDeque, HashSet, LinkedList};
use smallvec::SmallVec;

pub fn build_indexing_pipeline(documents: Vec<String>, keywords: HashSet<String>) -> 
    (BTreeMap<String, Vec<usize>>, VecDeque<String>, HashSet<String>, SmallVec<[usize; 8]>, LinkedList<String>) {

    // Initialize the return values
    let mut keyword_positions: BTreeMap<String, Vec<usize>> = BTreeMap::new();
    let mut processing_queue: VecDeque<String> = VecDeque::new();
    let mut indexed_docs: HashSet<String> = HashSet::new();
    let mut position_buffer: SmallVec<[usize; 8]> = SmallVec::new();
    let mut processing_log: LinkedList<String> = LinkedList::new();

    // Pre-populate the keyword_positions with empty vectors for each keyword
    for keyword in &keywords {
        keyword_positions.insert(keyword.clone(), Vec::new());
    }

    // Add all documents to the processing queue
    for doc in documents {
        processing_queue.push_back(doc);
    }

    // Process the first document if available
    if let Some(doc) = processing_queue.pop_front() {
        processing_log.push_back("Started processing document".to_string());

        // Generate a document ID (here just using a hash of the content)
        let doc_id = format!("doc_{}", doc.len());

        // Process the document to find keywords
        let words: Vec<&str> = doc.split_whitespace().collect();

        for (pos, word) in words.iter().enumerate() {
            if keywords.contains(*word) {
                // Record the position
                if let Some(positions) = keyword_positions.get_mut(*word) {
                    positions.push(pos);
                    position_buffer.push(pos);
                    processing_log.push_back(format!("Found keyword '{}' at position {}", word, pos));
                }
            }
        }

        // Sort positions for each keyword (they might already be sorted based on the traversal,
        // but ensuring they are sorted as specified)
        for positions in keyword_positions.values_mut() {
            positions.sort_unstable();
        }

        // Mark document as indexed
        indexed_docs.insert(doc_id);
        processing_log.push_back("Completed processing document".to_string());
    }

    (keyword_positions, processing_queue, indexed_docs, position_buffer, processing_log)
}
