use std::collections::{BTreeMap, BTreeSet, VecDeque};
use arrayvec::ArrayVec;

struct Transaction {
    account_id: String,
    amount: f64,
}

enum TransactionType {
    Deposit,
    Withdrawal,
}

struct ProcessedTransaction {
    account_id: String,
    amount: f64,
    transaction_type: TransactionType,
    status: TransactionStatus,
}

enum TransactionStatus {
    Successful,
    Failed,
}

fn manage_account_transactions(transactions: Vec<Transaction>) -> (
    VecDeque<Transaction>,
    BTreeMap<String, f64>,
    BTreeSet<String>,
    ArrayVec<[ProcessedTransaction; 5]>,
) {
    let mut pending_transactions = VecDeque::new();
    let mut account_balances = BTreeMap::new();
    let mut flagged_accounts = BTreeSet::new();
    let mut recent_transactions = ArrayVec::<[ProcessedTransaction; 5]>::new();

    for transaction in transactions {
        let transaction_type = if transaction.amount >= 0.0 {
            TransactionType::Deposit
        } else {
            TransactionType::Withdrawal
        };

        let balance = account_balances.entry(transaction.account_id.clone()).or_insert(0.0);

        let status = match transaction_type {
            TransactionType::Deposit => {
                *balance += transaction.amount.abs();

                // Flag accounts with unusually high deposits (over 10000)
                if transaction.amount.abs() > 10000.0 {
                    flagged_accounts.insert(transaction.account_id.clone());
                }

                TransactionStatus::Successful
            },
            TransactionType::Withdrawal => {
                if *balance >= transaction.amount.abs() {
                    *balance -= transaction.amount.abs();

                    // Flag accounts with unusually high withdrawals (over 5000)
                    if transaction.amount.abs() > 5000.0 {
                        flagged_accounts.insert(transaction.account_id.clone());
                    }

                    TransactionStatus::Successful
                } else {
                    pending_transactions.push_back(transaction.clone());
                    TransactionStatus::Failed
                }
            },
        };

        // Keep track of the most recent 5 transactions
        if recent_transactions.len() == 5 {
            recent_transactions.remove(0);
        }

        recent_transactions.push(ProcessedTransaction {
            account_id: transaction.account_id.clone(),
            amount: transaction.amount,
            transaction_type,
            status,
        });
    }

    (pending_transactions, account_balances, flagged_accounts, recent_transactions)
}
