        *current_quantity += quantity_change;

        // Track out of stock items
        if *current_quantity <= 0 {
            out_of_stock.insert(product_id.clone());
        } else {
            out_of_stock.remove(&product_id);
        }

        // Track incoming products
        if quantity_change > 0 {
            if !incoming_batch.is_full() {
                incoming_batch.push((product_id, quantity_change));
            }
        }
    }

    (inventory, out_of_stock, incoming_batch)
}
